   905тЖТ## 4.2.7 Route Utilization Service (NEW v2.1)
   906тЖТ
   907тЖТ### 4.2.7.1 Purpose
   908тЖТ
   909тЖТProvide route-specific daily mileage rates for accurate long-term projections. Using fleet-wide averages can result in 60,000+ km projection error over 12 years.
   910тЖТ
   911тЖТ### 4.2.7.2 Implementation
   912тЖТ
   913тЖТ```typescript
   914тЖТinterface RouteUtilizationProfile {
   915тЖТ  id: string;
   916тЖТ  routeId: string;
   917тЖТ  effectiveDate: Date;
   918тЖТ  
   919тЖТ  weekdayKm: number;
   920тЖТ  saturdayKm?: number;
   921тЖТ  sundayKm?: number;
   922тЖТ  holidayKm?: number;
   923тЖТ  
   924тЖТ  peakSeasonMultiplier: number;
   925тЖТ  offPeakMultiplier: number;
   926тЖТ  
   927тЖТ  confidence: 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
   928тЖТ}
   929тЖТ
   930тЖТclass RouteUtilizationService {
   931тЖТ  constructor(private db: Database) {}
   932тЖТ  
   933тЖТ  /**
   934тЖТ   * Get utilization profile for a route
   935тЖТ   */
   936тЖТ  async getProfile(routeId: string, asOfDate?: Date): Promise<RouteUtilizationProfile | null> {
   937тЖТ    const date = asOfDate || new Date();
   938тЖТ    
   939тЖТ    const profile = await this.db
   940тЖТ      .select()
   941тЖТ      .from(routeUtilizationProfiles)
   942тЖТ      .where(and(
   943тЖТ        eq(routeUtilizationProfiles.routeId, routeId),
   944тЖТ        lte(routeUtilizationProfiles.effectiveDate, date)
   945тЖТ      ))
   946тЖТ      .orderBy(desc(routeUtilizationProfiles.effectiveDate))
   947тЖТ      .limit(1);
   948тЖТ    
   949тЖТ    return profile[0] || null;
   950тЖТ  }
   951тЖТ  
   952тЖТ  /**
   953тЖТ   * Calculate expected daily km for a train based on typical route assignment
   954тЖТ   */
   955тЖТ  async calculateDailyRate(
   956тЖТ    trainId: string, 
   957тЖТ    targetDate: Date
   958тЖТ  ): Promise<{ dailyKm: number; source: string; confidence: string }> {
   959тЖТ    // 1. Check for explicit route assignment
   960тЖТ    const assignment = await this.getTypicalRouteAssignment(trainId);
   961тЖТ    
   962тЖТ    if (assignment) {
   963тЖТ      const profile = await this.getProfile(assignment.routeId, targetDate);
   964тЖТ      if (profile) {
   965тЖТ        const dayType = this.getDayType(targetDate);
   966тЖТ        const baseKm = this.getKmForDayType(profile, dayType);
   967тЖТ        const seasonalMultiplier = this.getSeasonalMultiplier(profile, targetDate);
   968тЖТ        
   969тЖТ        return {
   970тЖТ          dailyKm: Math.round(baseKm * seasonalMultiplier),
   971тЖТ          source: `route:${assignment.routeId}`,
   972тЖТ          confidence: profile.confidence
   973тЖТ        };
   974тЖТ      }
   975тЖТ    }
   976тЖТ    
   977тЖТ    // 2. Fall back to fleet average
   978тЖТ    const train = await this.db
   979тЖТ      .select({ fleetId: trains.fleetId })
   980тЖТ      .from(trains)
   981тЖТ      .where(eq(trains.id, trainId))
   982тЖТ      .limit(1);
   983тЖТ    
   984тЖТ    if (train[0]) {
   985тЖТ      const fleetAverage = await this.getFleetAverage(train[0].fleetId);
   986тЖТ      return {
   987тЖТ        dailyKm: fleetAverage,
   988тЖТ        source: 'fleet_average',
   989тЖТ        confidence: 'LOW'
   990тЖТ      };
   991тЖТ    }
   992тЖТ    
   993тЖТ    // 3. System default
   994тЖТ    return {
   995тЖТ      dailyKm: 250,  // Conservative default
   996тЖТ      source: 'system_default',
   997тЖТ      confidence: 'ESTIMATED'
   998тЖТ    };
   999тЖТ  }
  1000тЖТ  
  1001тЖТ  /**
  1002тЖТ   * Project mileage for a train over a time horizon
  1003тЖТ   */
  1004тЖТ  async projectMileage(
  1005тЖТ    trainId: string,
  1006тЖТ    startDate: Date,
  1007тЖТ    horizonDays: number
  1008тЖТ  ): Promise<{ date: Date; projectedKm: number; cumulativeKm: number }[]> {
  1009тЖТ    const train = await this.db
  1010тЖТ      .select()
  1011тЖТ      .from(trains)
  1012тЖТ      .where(eq(trains.id, trainId))
  1013тЖТ      .limit(1);
  1014тЖТ    
  1015тЖТ    if (!train[0]) {
  1016тЖТ      throw new NotFoundError(`Train ${trainId} not found`);
  1017тЖТ    }
  1018тЖТ    
  1019тЖТ    let cumulativeKm = train[0].currentMileageKm;
  1020тЖТ    const projections: { date: Date; projectedKm: number; cumulativeKm: number }[] = [];
  1021тЖТ    
  1022тЖТ    for (let day = 0; day < horizonDays; day++) {
  1023тЖТ      const targetDate = addDays(startDate, day);
  1024тЖТ      const { dailyKm } = await this.calculateDailyRate(trainId, targetDate);
  1025тЖТ      
  1026тЖТ      cumulativeKm += dailyKm;
  1027тЖТ      projections.push({
  1028тЖТ        date: targetDate,
  1029тЖТ        projectedKm: dailyKm,
  1030тЖТ        cumulativeKm
  1031тЖТ      });
  1032тЖТ    }
  1033тЖТ    
  1034тЖТ    return projections;
  1035тЖТ  }
  1036тЖТ  
  1037тЖТ  private async getTypicalRouteAssignment(trainId: string): Promise<{ routeId: string } | null> {
  1038тЖТ    // Look at recent run assignments to determine typical route
  1039тЖТ    const recentAssignments = await this.db
  1040тЖТ      .select({ routeId: runAssignments.routeId, count: count() })
  1041тЖТ      .from(runAssignments)
  1042тЖТ      .where(and(
  1043тЖТ        eq(runAssignments.trainId, trainId),
  1044тЖТ        gte(runAssignments.assignmentDate, addDays(new Date(), -30))
  1045тЖТ      ))
  1046тЖТ      .groupBy(runAssignments.routeId)
  1047тЖТ      .orderBy(desc(count()))
  1048тЖТ      .limit(1);
  1049тЖТ    
  1050тЖТ    return recentAssignments[0] || null;
  1051тЖТ  }
  1052тЖТ  
  1053тЖТ  private async getFleetAverage(fleetId: string): Promise<number> {
  1054тЖТ    // Calculate from recent mileage readings
  1055тЖТ    const result = await this.db
  1056тЖТ      .select({ avgDaily: avg(mileageReadings.dailyKm) })
  1057тЖТ      .from(mileageReadings)
  1058тЖТ      .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
  1059тЖТ      .where(and(
  1060тЖТ        eq(trains.fleetId, fleetId),
  1061тЖТ        gte(mileageReadings.readingDate, addDays(new Date(), -30)),
  1062тЖТ        eq(mileageReadings.validationStatus, 'VALID')
  1063тЖТ      ));
  1064тЖТ    
  1065тЖТ    return Math.round(result[0]?.avgDaily || 250);
  1066тЖТ  }
  1067тЖТ  
  1068тЖТ  private getKmForDayType(profile: RouteUtilizationProfile, dayType: string): number {
  1069тЖТ    switch (dayType) {
  1070тЖТ      case 'SATURDAY': return profile.saturdayKm || profile.weekdayKm * 0.8;
  1071тЖТ      case 'SUNDAY': return profile.sundayKm || profile.weekdayKm * 0.7;
  1072тЖТ      case 'HOLIDAY': return profile.holidayKm || profile.weekdayKm * 0.6;
  1073тЖТ      default: return profile.weekdayKm;
  1074тЖТ    }
  1075тЖТ  }
  1076тЖТ  
  1077тЖТ  private getSeasonalMultiplier(profile: RouteUtilizationProfile, date: Date): number {
  1078тЖТ    // TODO: Integrate with season calendar
  1079тЖТ    const month = date.getMonth();
  1080тЖТ    // Peak season: CNY (Jan-Feb), School holidays (Jun, Nov-Dec)
  1081тЖТ    const peakMonths = [0, 1, 5, 10, 11];
  1082тЖТ    return peakMonths.includes(month) ? profile.peakSeasonMultiplier : profile.offPeakMultiplier;
  1083тЖТ  }
  1084тЖТ  
  1085тЖТ  private getDayType(date: Date): string {
  1086тЖТ    const dayOfWeek = date.getDay();
  1087тЖТ    if (dayOfWeek === 0) return 'SUNDAY';
  1088тЖТ    if (dayOfWeek === 6) return 'SATURDAY';
  1089тЖТ    return 'WEEKDAY';
  1090тЖТ  }
  1091тЖТ}
