  1096тЖТ## 4.3 Run Assignment Optimizer
  1097тЖТ
  1098тЖТ### 4.3.1 Purpose
  1099тЖТ
  1100тЖТOptimize daily train-to-route assignments for mileage balancing while respecting hard constraints (fitness, PM due, **unavailability**, **service demand**) and minimizing soft constraint penalties.
  1101тЖТ
  1102тЖТ### 4.3.2 Optimizer Service (TypeScript Wrapper)
  1103тЖТ
  1104тЖТ```typescript
  1105тЖТinterface OptimizerConfig {
  1106тЖТ  binaryPath: string;          // ./mms-optimizer
  1107тЖТ  maxSolveTimeSeconds: number; // 30
  1108тЖТ  numWorkers: number;          // 4
  1109тЖТ  timeoutMs: number;           // 60000
  1110тЖТ  fallbackEnabled: boolean;    // true
  1111тЖТ}
  1112тЖТ
  1113тЖТclass RunAssignmentOptimizer {
  1114тЖТ  private process: Subprocess | null = null;
  1115тЖТ  
  1116тЖТ  async optimize(input: OptimizerInput): Promise<OptimizerResult> {
  1117тЖТ    const startTime = Date.now();
  1118тЖТ    
  1119тЖТ    try {
  1120тЖТ      // Try C++ optimizer first
  1121тЖТ      const result = await this.runCppOptimizer(input);
  1122тЖТ      
  1123тЖТ      // Validate result
  1124тЖТ      if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
  1125тЖТ        this.logger.warn('C++ optimizer returned INFEASIBLE, using fallback');
  1126тЖТ        return await this.runFallbackOptimizer(input);
  1127тЖТ      }
  1128тЖТ      
  1129тЖТ      return result;
  1130тЖТ      
  1131тЖТ    } catch (error) {
  1132тЖТ      this.logger.error({ error }, 'C++ optimizer failed, using fallback');
  1133тЖТ      
  1134тЖТ      if (this.config.fallbackEnabled) {
  1135тЖТ        return await this.runFallbackOptimizer(input);
  1136тЖТ      }
  1137тЖТ      
  1138тЖТ      throw error;
  1139тЖТ    }
  1140тЖТ  }
  1141тЖТ  
  1142тЖТ  private async runCppOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1143тЖТ    return new Promise((resolve, reject) => {
  1144тЖТ      const timeout = setTimeout(() => {
  1145тЖТ        this.process?.kill();
  1146тЖТ        reject(new Error('Optimizer timeout'));
  1147тЖТ      }, this.config.timeoutMs);
  1148тЖТ      
  1149тЖТ      this.process = Bun.spawn([this.config.binaryPath], {
  1150тЖТ        stdin: 'pipe',
  1151тЖТ        stdout: 'pipe',
  1152тЖТ        stderr: 'pipe'
  1153тЖТ      });
  1154тЖТ      
  1155тЖТ      // Write input
  1156тЖТ      const writer = this.process.stdin.getWriter();
  1157тЖТ      writer.write(new TextEncoder().encode(JSON.stringify(input) + '\n'));
  1158тЖТ      writer.close();
  1159тЖТ      
  1160тЖТ      // Read stdout (results)
  1161тЖТ      const results: any[] = [];
  1162тЖТ      const reader = this.process.stdout.getReader();
  1163тЖТ      const decoder = new TextDecoder();
  1164тЖТ      let buffer = '';
  1165тЖТ      
  1166тЖТ      const readStream = async () => {
  1167тЖТ        while (true) {
  1168тЖТ          const { done, value } = await reader.read();
  1169тЖТ          if (done) break;
  1170тЖТ          
  1171тЖТ          buffer += decoder.decode(value, { stream: true });
  1172тЖТ          const lines = buffer.split('\n');
  1173тЖТ          buffer = lines.pop() || '';
  1174тЖТ          
  1175тЖТ          for (const line of lines) {
  1176тЖТ            if (!line.trim()) continue;
  1177тЖТ            
  1178тЖТ            try {
  1179тЖТ              const msg = JSON.parse(line);
  1180тЖТ              
  1181тЖТ              if (msg.type === 'PROGRESS') {
  1182тЖТ                this.emitProgress(msg);
  1183тЖТ              } else if (msg.type === 'RESULT') {
  1184тЖТ                clearTimeout(timeout);
  1185тЖТ                resolve(this.mapResult(msg));
  1186тЖТ                return;
  1187тЖТ              }
  1188тЖТ            } catch (e) {
  1189тЖТ              this.logger.warn({ line }, 'Failed to parse optimizer output');
  1190тЖТ            }
  1191тЖТ          }
  1192тЖТ        }
  1193тЖТ      };
  1194тЖТ      
  1195тЖТ      // Read stderr (metrics/logs)
  1196тЖТ      this.readStderr(this.process.stderr);
  1197тЖТ      
  1198тЖТ      readStream().catch(reject);
  1199тЖТ      
  1200тЖТ      this.process.exited.then((code) => {
  1201тЖТ        clearTimeout(timeout);
  1202тЖТ        if (code !== 0 && results.length === 0) {
  1203тЖТ          reject(new Error(`Optimizer exited with code ${code}`));
  1204тЖТ        }
  1205тЖТ      });
  1206тЖТ    });
  1207тЖТ  }
  1208тЖТ  
  1209тЖТ  private async runFallbackOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1210тЖТ    // TypeScript greedy fallback
  1211тЖТ    const assignments: Assignment[] = [];
  1212тЖТ    const unassigned: UnassignedTrain[] = [];
  1213тЖТ    const assignedTrainIds = new Set<string>();
  1214тЖТ    
  1215тЖТ    // Sort routes by priority (required trains desc)
  1216тЖТ    const sortedRoutes = [...input.routes].sort(
  1217тЖТ      (a, b) => b.required_trains - a.required_trains
  1218тЖТ    );
  1219тЖТ    
  1220тЖТ    // Sort trains by fitness and mileage balance
  1221тЖТ    const sortedTrains = [...input.trains]
  1222тЖТ      .filter(t => t.fitness_status === 'FIT')
  1223тЖТ      .sort((a, b) => {
  1224тЖТ        // Prioritize under-utilized trains
  1225тЖТ        const aBalance = a.current_mileage - a.target_mileage;
  1226тЖТ        const bBalance = b.current_mileage - b.target_mileage;
  1227тЖТ        return aBalance - bBalance;
  1228тЖТ      });
  1229тЖТ    
  1230тЖТ    for (const route of sortedRoutes) {
  1231тЖТ      let assigned = 0;
  1232тЖТ      
  1233тЖТ      for (const train of sortedTrains) {
  1234тЖТ        if (assigned >= route.required_trains) break;
  1235тЖТ        if (assignedTrainIds.has(train.id)) continue;
  1236тЖТ        
  1237тЖТ        // Check hard constraints
  1238тЖТ        const hardViolation = this.checkHardConstraints(train, route, input);
  1239тЖТ        if (hardViolation) {
  1240тЖТ          continue;
  1241тЖТ        }
  1242тЖТ        
  1243тЖТ        // Check fleet compatibility
  1244тЖТ        if (route.allowed_fleets.length > 0 && 
  1245тЖТ            !route.allowed_fleets.includes(train.fleet_id)) {
  1246тЖТ          continue;
  1247тЖТ        }
  1248тЖТ        
  1249тЖТ        // Assign
  1250тЖТ        assignments.push({
  1251тЖТ          train_id: train.id,
  1252тЖТ          route_id: route.id,
  1253тЖТ          score: this.calculateScore(train, route),
  1254тЖТ          explanation: [
  1255тЖТ            {
  1256тЖТ              constraint_type: 'SOFT',
  1257тЖТ              constraint_name: 'MILEAGE_BALANCE',
  1258тЖТ              impact: train.current_mileage - train.target_mileage,
  1259тЖТ              description: `Train is ${Math.abs(train.current_mileage - train.target_mileage)}km ${
  1260тЖТ                train.current_mileage < train.target_mileage ? 'under' : 'over'
  1261тЖТ              } target`
  1262тЖТ            }
  1263тЖТ          ]
  1264тЖТ        });
  1265тЖТ        
  1266тЖТ        assignedTrainIds.add(train.id);
  1267тЖТ        assigned++;
  1268тЖТ      }
  1269тЖТ      
  1270тЖТ      // Record shortfall
  1271тЖТ      if (assigned < route.required_trains) {
  1272тЖТ        unassigned.push({
  1273тЖТ          route_id: route.id,
  1274тЖТ          shortfall: route.required_trains - assigned,
  1275тЖТ          reason: 'Insufficient fit trains available'
  1276тЖТ        });
  1277тЖТ      }
  1278тЖТ    }
  1279тЖТ    
  1280тЖТ    // Record unassigned trains with reasons
