  1476тЖТ
  1477тЖТclass MmsSolver {
  1478тЖТpublic:
  1479тЖТ    json solve(const json& input) {
  1480тЖТ        CpModelBuilder model;
  1481тЖТ        std::string request_id = input["request_id"];
  1482тЖТ        
  1483тЖТ        auto trains = input["trains"];
  1484тЖТ        auto routes = input["routes"];
  1485тЖТ        auto config = input["config"];
  1486тЖТ        
  1487тЖТ        // Decision variables: assign[t][r] = 1 if train t assigned to route r
  1488тЖТ        std::vector<std::vector<BoolVar>> assign;
  1489тЖТ        assign.resize(trains.size());
  1490тЖТ        
  1491тЖТ        for (size_t t = 0; t < trains.size(); t++) {
  1492тЖТ            assign[t].resize(routes.size());
  1493тЖТ            for (size_t r = 0; r < routes.size(); r++) {
  1494тЖТ                assign[t][r] = model.NewBoolVar();
  1495тЖТ            }
  1496тЖТ        }
  1497тЖТ        
  1498тЖТ        // Hard constraint: Each train assigned to at most one route
  1499тЖТ        for (size_t t = 0; t < trains.size(); t++) {
  1500тЖТ            std::vector<BoolVar> train_routes;
  1501тЖТ            for (size_t r = 0; r < routes.size(); r++) {
  1502тЖТ                train_routes.push_back(assign[t][r]);
  1503тЖТ            }
  1504тЖТ            model.AddAtMostOne(train_routes);
  1505тЖТ        }
  1506тЖТ        
  1507тЖТ        // Hard constraint: Route requirements (exactly N trains)
  1508тЖТ        for (size_t r = 0; r < routes.size(); r++) {
  1509тЖТ            std::vector<BoolVar> route_trains;
  1510тЖТ            for (size_t t = 0; t < trains.size(); t++) {
  1511тЖТ                // Check fleet compatibility
  1512тЖТ                if (isFleetAllowed(trains[t], routes[r])) {
  1513тЖТ                    route_trains.push_back(assign[t][r]);
  1514тЖТ                }
  1515тЖТ            }
  1516тЖТ            
  1517тЖТ            int required = routes[r]["required_trains"];
  1518тЖТ            model.AddEquality(LinearExpr::Sum(route_trains), required);
  1519тЖТ        }
  1520тЖТ        
  1521тЖТ        // Hard constraint: Fitness status
  1522тЖТ        for (size_t t = 0; t < trains.size(); t++) {
  1523тЖТ            if (trains[t]["fitness_status"] != "FIT") {
  1524тЖТ                for (size_t r = 0; r < routes.size(); r++) {
  1525тЖТ                    model.AddEquality(assign[t][r], 0);
  1526тЖТ                }
  1527тЖТ            }
  1528тЖТ        }
  1529тЖТ        
  1530тЖТ        // Hard constraints from input
  1531тЖТ        for (const auto& constraint : input["hard_constraints"]) {
  1532тЖТ            size_t train_idx = findTrainIndex(trains, constraint["train_id"]);
  1533тЖТ            if (train_idx < trains.size()) {
  1534тЖТ                for (size_t r = 0; r < routes.size(); r++) {
  1535тЖТ                    model.AddEquality(assign[train_idx][r], 0);
  1536тЖТ                }
  1537тЖТ            }
  1538тЖТ        }
  1539тЖТ        
  1540тЖТ        // NEW v2.1: Hard constraint - Unavailability events
  1541тЖТ        if (input.contains("unavailability_events")) {
  1542тЖТ            for (const auto& event : input["unavailability_events"]) {
  1543тЖТ                if (event["status"] == "ACTIVE" && event["blocks_run_assignment"].get<bool>()) {
  1544тЖТ                    size_t train_idx = findTrainIndex(trains, event["train_id"]);
  1545тЖТ                    if (train_idx < trains.size()) {
  1546тЖТ                        for (size_t r = 0; r < routes.size(); r++) {
  1547тЖТ                            model.AddEquality(assign[train_idx][r], 0);
  1548тЖТ                        }
  1549тЖТ                    }
  1550тЖТ                }
  1551тЖТ            }
  1552тЖТ        }
  1553тЖТ        
  1554тЖТ        // NEW v2.1: Hard constraint - Route compatibility
  1555тЖТ        if (input.contains("route_compatibility")) {
  1556тЖТ            for (const auto& compat : input["route_compatibility"]) {
  1557тЖТ                if (!compat["is_compatible"].get<bool>()) {
  1558тЖТ                    size_t train_idx = findTrainIndex(trains, compat["train_id"]);
  1559тЖТ                    size_t route_idx = findRouteIndex(routes, compat["route_id"]);
  1560тЖТ                    if (train_idx < trains.size() && route_idx < routes.size()) {
  1561тЖТ                        model.AddEquality(assign[train_idx][route_idx], 0);
  1562тЖТ                    }
  1563тЖТ                }
  1564тЖТ            }
  1565тЖТ        }
  1566тЖТ        
  1567тЖТ        // Soft constraint: Mileage balance
  1568тЖТ        std::vector<IntVar> mileage_penalties;
