  1570тЖТ        int mileage_weight = penalties["mileage_imbalance"].get<int>();
  1571тЖТ        
  1572тЖТ        for (size_t t = 0; t < trains.size(); t++) {
  1573тЖТ            int current = trains[t]["current_mileage"];
  1574тЖТ            int target = trains[t]["target_mileage"];
  1575тЖТ            int variance = std::abs(current - target);
  1576тЖТ            
